import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{t as i}from"./chunks/custom-arguments_fail.CHyUHi1U.js";import{n as a,t as o}from"./chunks/custom-arguments_result.DON41wDu.js";const s=JSON.parse(`{"title":"Befehlsargumente","description":"Lerne, wie man Befehle mit komplexen Parametern erstellt.","frontmatter":{"title":"Befehlsargumente","description":"Lerne, wie man Befehle mit komplexen Parametern erstellt.","search":false,"files":["@/reference/latest/src/main/java/com/example/docs/command/ExampleModCommands.java"]},"headers":[],"relativePath":"de_de/1.20.4/develop/commands/arguments.md","filePath":"versions/1.20.4/translated/de_de/develop/commands/arguments.md","lastUpdated":1760369273000}`);var c={name:`de_de/1.20.4/develop/commands/arguments.md`};function l(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Befehlsargumente <a class="header-anchor" href="#h1" aria-label="Permalink to “Befehlsargumente”">​</a></h1><p>Parameter werden in den meisten Befehlen verwendet. Manchmal sind sie optional, das heißt, wenn du diesen Parameter nicht angibst, wird der Befehl dennoch ausgeführt. Ein Knoten kann mehrere Parametertypen haben, aber es ist zu beachten, dass die Möglichkeit einer Mehrdeutigkeit besteht, die vermieden werden sollte.</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>In diesem Fall musst du nach dem Befehlstext <code>/argtater</code> eine ganze Zahl eingeben. Zum Beispiel, wenn du <code>/argtater 3</code> ausführst, erhaltest du die Rückmeldung <code>Called /argtater with value = 3</code>. Wenn du <code>/argtater</code> ohne Argumente eingibst, kann der Befehl nicht korrekt geparst werden.</p><p>Dann fügen wir ein optionales zweites Argument hinzu:</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Jetzt kannst du eine oder zwei ganze Zahlen eingeben. Wenn du eine ganze Zahl eingibst, wird ein Feedback-Text mit einem einzigen Wert ausgegeben. Wenn du zwei Ganzzahlen angibst, wird ein Feedback-Text mit zwei Werten ausgegeben.</p><p>Du kannst es unnötig finden, ähnliche Ausführungen zweimal anzugeben. Daher können wir eine Methode erstellen, die in beiden Ausführungen verwendet wird.</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="benutzerdefinierte-argumenttypen" tabindex="-1">Benutzerdefinierte Argumenttypen <a class="header-anchor" href="#benutzerdefinierte-argumenttypen" aria-label="Permalink to “Benutzerdefinierte Argumenttypen”">​</a></h2><p>Wenn Vanilla nicht den von dir benötigten Argumenttyp verfügt, kannst du deinen eigenen erstellen. Dazu musst du eine Klasse erstellen, die das Interface <code>ArgumentType&lt;T&gt;</code> erbt, wobei <code>T</code> der Typ des Arguments ist.</p><p>Du musst die Methode &quot;parse&quot; implementieren, die die Eingabezeichenfolge zu dem gewünschten Typ parst.</p><p>Du kannst zum Beispiel einen Argumenttyp erstellen, der eine <code>BlockPos</code> aus einer Zeichenkette mit dem folgenden Format parst: <code>{x, y, z}</code></p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="benutzerdefinierte-argumenttypen-registrieren" tabindex="-1">Benutzerdefinierte Argumenttypen registrieren <a class="header-anchor" href="#benutzerdefinierte-argumenttypen-registrieren" aria-label="Permalink to “Benutzerdefinierte Argumenttypen registrieren”">​</a></h3><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Du musst den benutzerdefinierten Argumenttyp sowohl im Server als auch im Client registrieren, sonst wird der Befehl nicht funktionieren!</p></div><p>Du kannst deinen benutzerdefinierten Argumenttyp in der Methode <code>onInitialize</code> deines Mod-Initialisierers mit der Klasse <code>ArgumentTypeRegistry</code> registrieren:</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="benutzerdefinierte-argumenttypen-verwenden" tabindex="-1">Benutzerdefinierte Argumenttypen verwenden <a class="header-anchor" href="#benutzerdefinierte-argumenttypen-verwenden" aria-label="Permalink to “Benutzerdefinierte Argumenttypen verwenden”">​</a></h3><p>Wir können unseren benutzerdefinierten Argumenttyp in einem Befehl verwenden, indem wir eine Instanz davon an die Methode <code>.argument</code> im Builder des Befehls übergeben.</p><div class="language-java line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">java</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">No lines matched.</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Durch das Ausführen des Befehls, können wir testen, ob der Argumenttyp funktioniert oder nicht:</p><p><img src="/assets/develop/commands/custom-arguments_fail.png" alt="Ungültiges Argument" loading="lazy"></p><p><img src="/assets/develop/commands/custom-arguments_valid.png" alt="Gültiges Argument" loading="lazy"></p><p><img src="/assets/develop/commands/custom-arguments_result.png" alt="Ergebnis des Befehls" loading="lazy"></p>`,25)]])}var u=r(c,[[`render`,l]]);export{s as __pageData,u as default};